SELECT SUM(payment_amount) AS total_cash_payment
FROM trade_payments
WHERE payment_method = 'cash' AND payment_date LIKE '2022%';

SELECT trade_date
FROM trade_data
ORDER BY trade_date DESC;

SELECT SUM(total_value) AS total_trade_value
FROM trade_data
WHERE source_country_id = (SELECT country_id FROM countries WHERE country_name = 'Luxembourg');

SELECT SUM(total_value) AS total_trade_value
FROM trade_data
WHERE commodity_id = 1;
